use strict;use warnings;
use Path::Tiny;

my @papers = qw(PMC10995391.md PMC2916058.md PMC6813860.md);

sub load_terms {
  my ($path)=@_;
  my @terms;
  for my $line (path($path)->lines_utf8({chomp=>1})) {
    $line =~ s/^\s+|\s+$//g;
    next if $line eq '';
    push @terms, lc($line);
  }
  return \@terms;
}

sub tokenize {
  my ($s)=@_;
  $s = lc($s // '');
  my @t = ($s =~ /[a-z0-9]+/g);
  return \@t;
}

sub build_index {
  my ($terms)=@_;
  my %idx;
  for my $term (@$terms) {
    my $toks = tokenize($term);
    next unless @$toks;
    push @{ $idx{$toks->[0]} }, [$toks, $term];
  }
  # sort by descending length for minor speed
  for my $k (keys %idx) {
    my @sorted = sort { scalar(@{$b->[0]}) <=> scalar(@{$a->[0]}) } @{ $idx{$k} };
    $idx{$k} = \@sorted;
  }
  return \%idx;
}

sub find_terms {
  my ($idx, $text)=@_;
  my $tokens = tokenize($text);
  my %found;
  my $n = scalar(@$tokens);
  for (my $i=0; $i<$n; $i++) {
    my $tok = $tokens->[$i];
    my $cands = $idx->{$tok};
    next unless $cands;
    CAND: for my $cand (@$cands) {
      my ($tt, $term) = @$cand;
      my $L = scalar(@$tt);
      next if $i + $L > $n;
      for (my $j=0; $j<$L; $j++) {
        next CAND if $tokens->[$i+$j] ne $tt->[$j];
      }
      $found{$term}=1;
    }
  }
  return \%found;
}

my $drug_terms = load_terms('term_banks/drugs.txt');
my $phen_terms = load_terms('term_banks/phenotypes.txt');
my $idx_drugs = build_index($drug_terms);
my $idx_phens = build_index($phen_terms);

my %all_drugs; my %all_phens;
my %per;
for my $p (@papers) {
  my $text = path('papers')->child($p)->slurp_utf8;
  my $d = find_terms($idx_drugs, $text);
  my $ph = find_terms($idx_phens, $text);
  $per{$p} = { drugs => [sort keys %$d], phenotypes => [sort keys %$ph] };
  $all_drugs{$_}=1 for keys %$d;
  $all_phens{$_}=1 for keys %$ph;
}

print "Per-file matches:\n";
for my $p (@papers) {
  print "$p drugs=".scalar(@{$per{$p}->{drugs}})." phenotypes=".scalar(@{$per{$p}->{phenotypes}})."\n";
}
print "\nAll drugs (".scalar(keys %all_drugs)."):\n";
print join("\n", sort keys %all_drugs),"\n";
print "\nAll phenotypes (".scalar(keys %all_phens)."):\n";
print join("\n", sort keys %all_phens),"\n";
